function isCyclicShift(A, B) {
    const k = A.length;
    if (k === 0) return true;

    // Check all k possible left shifts of A against B
    // B[i] must equal A[(i + s) % k] for some shift s
    for (let s = 0; s < k; s++) {
        let match = true;
        for (let i = 0; i < k; i++) {
            const A_index = (i + s) % k;
            if (B[i] !== A[A_index]) {
                match = false;
                break;
            }
        }
        if (match) return true;
    }
    return false;
